        }
    }
}

# Link 5: Reference directory
$source5 = "$claudePath\reference"
$target5 = "$vaultPath\05-Reference\_claude-reference"

Write-Host "• Reference: " -NoNewline
if (Test-Path $target5) {
    Write-Host "Already exists" -ForegroundColor Yellow
} elseif (-not (Test-Path $source5)) {
    Write-Host "Source not found" -ForegroundColor Red
} else {
    if ($isAdmin) {
        New-Item -ItemType SymbolicLink -Path $target5 -Target $source5 -Force | Out-Null
        Write-Host "Created (symlink)" -ForegroundColor Green
    } else {
        cmd /c mklink /J "$target5" "$source5" 2>&1 | Out-Null
        if ($LASTEXITCODE -eq 0) {
            Write-Host "Created (junction)" -ForegroundColor Green
        } else {
            Write-Host "Failed" -ForegroundColor Red
        }
    }
}

# Verify
Write-Host ""
Write-Host "Verification:" -ForegroundColor White
if (Test-Path $target1) {
    Write-Host "  CLAUDE.md accessible" -ForegroundColor Green
} else {
    Write-Host "  CLAUDE.md NOT accessible" -ForegroundColor Red
}

Write-Host ""
Write-Host "Next steps:" -ForegroundColor Cyan
Write-Host "  1. Open Obsidian" -ForegroundColor White
Write-Host "  2. Open vault: $vaultPath" -ForegroundColor White
Write-Host "  3. Install Dataview plugin" -ForegroundColor White
Write-Host "  4. Open: 00-Dashboard/Context-Quality-Dashboard.md" -ForegroundColor White
Write-Host ""

Write-Host "Press any key to exit..."
$null = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown")
